const PROCESSING_FEE = 5;
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;
const COMPONENT_BASE = 25;
const FIRST_INS_SURCHARGE = 0.1;
const CURSE_SURCHARGE = 0.5;
const HIGH_ENCH_SURCHARGE = 0.3;
const HIGH_ENCH_THRESHOLD = 5;
const LOYALTY_DISCOUNT = 0.2;
const LOYALTY_THRESHOLD = 2;
const FOLLOW_UP_DISCOUNT = 0.15;
const DEDUCTIBLE = 100;
const HIGH_ENCH_CLAIM_THRESHOLD = 8;
const HIGH_ENCH_CLAIM_FACTOR = 0.5;
const INSURANCE_VALUE_MULTIPLIER = 10;

const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

export type Item = {
  type: string;
  enchantment?: number;
  cursed?: boolean;
  material?: string;
};

export type Customer = {
  yearsWithMHPCO?: number;
};

export type QuoteInput = {
  customer?: Customer;
  items: Item[];
  isFollowUp?: boolean;
};

export type QuoteResult = {
  premium: number;
};

export type DamageEntry = {
  itemType: string;
  amount: number;
};

export type Policy = {
  items: Item[];
  remainingCap: number;
};

export type Incident = {
  cause?: string;
  damages: DamageEntry[];
};

export type ClaimInput = {
  policy: Policy;
  incident: Incident;
};

export type ClaimResult = {
  payout: number;
  remainingCap: number;
};

export const insuranceValueFor = (item: Item): number =>
  (BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0) * INSURANCE_VALUE_MULTIPLIER;

const baseForItem = (item: Item): number =>
  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;

const isComponent = (item: Item): boolean =>
  COMPONENT_TYPES.has(item.type);

const itemModifierSum = (item: Item): number => {
  let mod = FIRST_INS_SURCHARGE;
  if (item.cursed) mod += CURSE_SURCHARGE;
  if ((item.enchantment ?? 0) >= HIGH_ENCH_THRESHOLD) mod += HIGH_ENCH_SURCHARGE;
  return mod;
};

const itemCharge = (item: Item): number =>
  baseForItem(item) * (1 + itemModifierSum(item));

const countByType = (items: Item[]): Record<string, number> => {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  return counts;
};

const componentsCharge = (items: Item[]): number => {
  const componentItems = items.filter(isComponent);
  const counts = countByType(componentItems);
  let total = 0;
  for (const type in counts) {
    const count = counts[type];
    if (count === BLOCK_SIZE) {
      total += BLOCK_PRICE * (1 + FIRST_INS_SURCHARGE);
    } else {
      total += count * COMPONENT_BASE * (1 + FIRST_INS_SURCHARGE);
    }
  }
  return total;
};

const componentsBase = (items: Item[]): number => {
  const componentItems = items.filter(isComponent);
  const counts = countByType(componentItems);
  let total = 0;
  for (const type in counts) {
    const count = counts[type];
    total += count === BLOCK_SIZE ? BLOCK_PRICE : count * COMPONENT_BASE;
  }
  return total;
};

const nonComponentsCharge = (items: Item[]): number =>
  items.filter((item) => !isComponent(item)).reduce((sum, item) => sum + itemCharge(item), 0);

const nonComponentsBase = (items: Item[]): number =>
  items.filter((item) => !isComponent(item)).reduce((sum, item) => sum + baseForItem(item), 0);

export function quote(input: QuoteInput): QuoteResult {
  const items = input.items;
  const itemTotal = nonComponentsCharge(items) + componentsCharge(items);
  const policyBase = nonComponentsBase(items) + componentsBase(items);
  const years = input.customer?.yearsWithMHPCO ?? 0;
  let policyModifiers = 0;
  if (years >= LOYALTY_THRESHOLD) policyModifiers -= LOYALTY_DISCOUNT;
  if (input.isFollowUp) policyModifiers -= FOLLOW_UP_DISCOUNT;
  const policyAdjustment = policyBase * policyModifiers;
  const raw = itemTotal + policyAdjustment + PROCESSING_FEE;
  const premium = Math.ceil(Math.round(raw * 1e8) / 1e8);
  return { premium };
}

export function claim(input: ClaimInput): ClaimResult {
  let payout = 0;
  for (const damageEntry of input.incident.damages) {
    const item = input.policy.items.find((i) => i.type === damageEntry.itemType);
    let amount = damageEntry.amount;
    if (item && (item.enchantment ?? 0) >= HIGH_ENCH_CLAIM_THRESHOLD) {
      amount = amount * HIGH_ENCH_CLAIM_FACTOR;
    }
    payout += amount - DEDUCTIBLE;
  }
  payout = Math.min(payout, input.policy.remainingCap);
  const remainingCap = input.policy.remainingCap - payout;
  return { payout, remainingCap };
}

import {
  quote,
  claim,
  insuranceValueFor,
  type Customer,
  type Item,
  type Policy,
  type Incident,
} from "./claim-office.js";

const CAP_MULTIPLIER = 2;

type QuoteStep = {
  op: "quote";
  items: Item[];
};

type ClaimStep = {
  op: "claim";
  policy: number;
  incident: Incident;
};

type Step = QuoteStep | ClaimStep;

type Scenario = {
  customer: Customer;
  steps: Step[];
};

const readStdin = async (): Promise<string> => {
  const chunks: Buffer[] = [];
  for await (const chunk of process.stdin) {
    chunks.push(chunk as Buffer);
  }
  return Buffer.concat(chunks).toString("utf8");
};

const policyCapFor = (items: Item[]): number =>
  items.reduce((sum, item) => sum + CAP_MULTIPLIER * insuranceValueFor(item), 0);

const handleQuote = (
  customer: Customer,
  step: QuoteStep,
  policies: Policy[],
): unknown => {
  const result = quote({ customer, items: step.items });
  policies.push({ items: step.items, remainingCap: policyCapFor(step.items) });
  return result;
};

const handleClaim = (step: ClaimStep, policies: Policy[]): unknown => {
  const policy = policies[step.policy];
  const result = claim({ policy, incident: step.incident });
  policy.remainingCap = result.remainingCap;
  return result;
};

const runStep = (
  customer: Customer,
  step: Step,
  policies: Policy[],
): unknown =>
  step.op === "quote"
    ? handleQuote(customer, step, policies)
    : handleClaim(step, policies);

const runScenario = (scenario: Scenario): unknown[] => {
  const policies: Policy[] = [];
  return scenario.steps.map((step) => runStep(scenario.customer, step, policies));
};

const main = async () => {
  const input = await readStdin();
  const scenario: Scenario = JSON.parse(input);
  const results = runScenario(scenario);
  process.stdout.write(JSON.stringify({ results }));
};

main().catch((err) => {
  process.stderr.write(String(err));
  process.exit(1);
});
